import React from 'react';
import robot from './Robot.jpg';
import rws from './RWS.jpg';
import regbot from './Regbot.jpg';
import redistrictor from './Redistrictor.jpg';
import './Projects.css';
class Projects extends React.Component{
    display = [
        {   "path": robot,
            "title":"Autonomous Race Car",
            "desc":"An autonomous race car focusing on computer vision and machine learning concepts.",
            "tags":[" Python,"," PyTorch,"," NVIDIA Jetson Nano,"," Arduino,"," C++,"," OpenCV", " Machine Learning"],
            "link":"https://github.com/Cthnn/VIP-Autonomous-Car",
            "backend":undefined
        },
        {   "path": rws,
            "title":"Random Wallpaper Selector",
            "desc":"An elegantly designed Android Application for users to switch up their wallpapers.",
            "tags":[" Android API,", " Java,", " Android Studio"],
            "link":"https://github.com/Cthnn/RWS",
            "backend":undefined
        },
        {   "path": regbot,
            "title":"SBU Registration Bot",
            "desc":"A script designed to ease students' registration procedure.",
            "tags":[" Javascript,"," Node.js,"," Puppeteer,"," CSS,"," HTML"],
            "link":"https://github.com/Cthnn/Registration-Bot",
            "backend":undefined
        },
        {   "path": redistrictor,
            "title":"Colts Redistrictor",
            "desc":"A group project working with US census data and GeoJson data. This project utilizes Stony Brook's Seawulf high performance cluster to balance state district boundaries based on compactness measure and population devation.",
            "tags":[" Java,"," React,"," Bootstrap,"," Python,"," Hibernate,"," Spring Boot,"," Big Data,", "SQL,"," JPA,"," Slurm,"," MPI,", " MultiProcessing"],
            "link":"https://github.com/Cthnn/CSE-416-Colts",
            "backend":"https://github.com/Cthnn/CSE-416-Colts-Backend"
        }
    ]
    render(){
        return(
            <div class="comp">
                <div class="project-content">
                    {
                        this.display.map(project =>(
                            <div class="project-card">
                                <div class="project-image-wrapper"><img class="proj-img" src={project.path}/></div>
                                <div class="project-text-wrapper">
                                    <h5>{project.title}</h5>
                                    <h3>{project.desc}</h3>
                                    <h4>Skills:{project.tags}</h4>
                                    {(project.backend == undefined&&<a href={project.link}>View Project</a>)}
                                    {(project.backend !== undefined&&<a href={project.link}>View Client</a>)}
                                    {(project.backend !== undefined &&<a href={project.backend}>View Server</a>)}
                                </div>
                            </div>
                            )
                        )
                    }
                </div>
            </div>   
        );
    }
}
export default Projects;