import me from './me.jpg';
import React from 'react';
import './About.css';
class About extends React.Component{
    render(){
        return(
            <div class="comp">
                <div class="about-content">
                    <div id="about-img-wrap">
                        <img id="me" src={me} alt="me"/>
                    </div>
                    <div id="about-text-wrap">
                        <h6>About</h6>
                        <h3>Ethan Cheung is a photographer and engineer studying at Stony Brook University majoring in Computer science. 
                            Ethan has developed projects in computer vision, mobile development, log management, and many more. 
                            Throughout various projects, Ethan has learned to pick up new technologies quickly, he is always interested in 
                            finding creative ways to solve problmes and is always ready to learn more. He has worked as an associate 
                            Software Engineer for Toysdiva Inc. utilizing his knowledge in machine learning, and he has interned at Datto 
                            working under the Cloud Eng team building tools to maintain cloud stability and automate tasks.<br/><br/>
                            Ethan is interested in computer vision, mobile development, automation, and photography. Outside of his studies,
                            Ethan loves to taking pictures, playing video games, and performing the chinese yo-yo 
                        </h3>
                    </div>
                </div>
            </div>
        );
    }
}
export default About;