import './App.css';
import React from 'react';
import Home from './components/home/Home.js';
import About from './components/about/About.js';
import Projects from './components/projects/Projects.js';
import Contact from './components/contact/Contact.js';

class App extends React.Component {
  state = {
    comp:"home"
  }
  switchComponent = (component)=>{
    this.setState({comp:component});
    if (["home","contact"].indexOf(component) >= 0){
      document.body.style.backgroundColor = "#3760A7";
      document.getElementById("app").className = "app";
    }else{
      document.body.style.backgroundColor = "#e3e3e3";
      document.getElementById("app").className = "app alt-app";

    }
  }
  render(){
    return (
      <div id="app" className="App">
        <div class="nav">
          <svg id="logo" xmlns="http://www.w3.org/2000/svg" viewBox="0 0 383.92 135.85"><path class="cls-1" d="M124.82,211.81c4.6,7.68,21,8.56,21.7,9.58.24.33-.86,1.74-1,2.11-1,2.06-4.87-.94-21.55,4.44,0,0-73.41,25.21-69.37,53.09,6.84,47.14,74.56,36.8,165.88,12.22,3.2-.87-16.62-5.92-19.68-4.61-19.54,8.34-67.72,27.28-119.56,12.85-14.64-4.07-21.08-17-19.65-21.19,5.75-17,64.87-55.47,109.94-53.71,2.1.08,6.16-8.08,3.67-6.67-9.57,5.38-39.43-5.48-44-16-1.17-2.67,6.34-5.42,8.12-6.28,56.14-27.09,69.75,16.15,74,4.51,0,0-11-16.48-32-21.24a64.12,64.12,0,0,0-45.46,8.45c-8.11,5.06-10.29,9.71-11.13,12.58C124,204,122.73,208.33,124.82,211.81Z" transform="translate(-54.44 -178.19)"/><path class="cls-1" d="M306.84,206c.38.36,3.19,6.33,3,5.85-5.27-11.12-27.32-52.79-78.59-23.33-58.9,33.84-59.71,122.29,0,113s109.46-57.34,182.63-31-36.29-31.61-86-11.12c-195.72,80.5-121.84-48.75-92.57-57.53,87.74-26.33,68.44,62.16,77.22,15.92Z" transform="translate(-54.44 -178.19)"/></svg>
        </div>
        <div id="nav" class="nav">
          <a href="#Home" class="nav-link" onClick={this.switchComponent.bind(this,"home")}>Home</a>
          <a href="#About" class="nav-link" onClick={this.switchComponent.bind(this,"abt")}>About</a>
          <a href="#Projects" class="nav-link" onClick={this.switchComponent.bind(this,"proj")}>Projects</a>
          <a href="#Contact" class="nav-link" onClick={this.switchComponent.bind(this,"contact")}>Contact</a>
        </div>
        {(this.state.comp == "home") &&<Home></Home>}
        {(this.state.comp == "abt") &&<About></About>}
        {(this.state.comp == "proj") &&<Projects></Projects>}
        {(this.state.comp == "contact") &&<Contact></Contact>}
      </div>
    );
  }
}

export default App;
